rows.customCode:
(() => {
  'use strict';

  if (window.__pcbw_cf_init) return;
  window.__pcbw_cf_init = true;

  const NS = '__pcbw_cf';
  const STORAGE_KEY = '__pcbw_cf_state';
  const SCHEMA_VERSION = 3;
  const MAX_EVENT_HISTORY = 420;
  const MAX_NOTIFICATIONS = 140;
  const MAX_DISCOVERIES = 220;
  const MAX_SNAPSHOTS = 20;
  const EVENT_COOLDOWN_TURNS = 3;

  const CONFIG = {
    ui: {
      title: 'Chronicle Foundry',
      defaultScreen: 'dashboard',
      screens: ['dashboard', 'map', 'party', 'inventory', 'contracts', 'timeline', 'codex', 'factions', 'settings', 'debug']
    },
    simulation: {
      travelHours: 6,
      campHours: 8,
      lowFoodWarning: 18,
      lowWaterWarning: 18,
      lowMedicineWarning: 6,
      fatigueWarning: 80,
      severeWeatherThreshold: 4
    },
    resources: {
      caps: {
        food: 260,
        water: 260,
        medicine: 90,
        salvage: 280,
        fuelCells: 120,
        relicShards: 40,
        signalKeys: 20
      },
      weightByCategory: {
        food: 0.6,
        water: 0.9,
        medicine: 0.2,
        salvage: 1.4,
        fuelCells: 1.2,
        relicShards: 0.8,
        signalKeys: 0.1
      }
    },
    eventWeights: {
      weatherFront: 10,
      hostileContact: 12,
      discovery: 11,
      factionEncounter: 10,
      resourceWindfall: 9,
      crewConflict: 8,
      contractLead: 7,
      diseaseRisk: 6,
      campReflection: 9
    },
    imagePrompt: {
      basePrefix: 'frontier expedition documentation, cinematic realism, practical survival gear, atmospheric environmental storytelling,',
      baseSuffix: ', continuity with current state, no text overlay, high detail, (negativePrompt:::cartoon, neon fantasy, low detail, malformed anatomy)'
    }
  };

  const FACTIONS = [
    { id: 'river-compact', name: 'River Compact', descriptor: 'Trade consortium controlling supply arteries.' },
    { id: 'embersynod', name: 'Ember Synod', descriptor: 'Archivist order preserving dangerous old-world records.' },
    { id: 'ironwardens', name: 'Iron Wardens', descriptor: 'Militarized security bloc enforcing strict frontier law.' },
    { id: 'verdant-covenant', name: 'Verdant Covenant', descriptor: 'Ecological coalition restoring biosystems and seed vaults.' },
    { id: 'glass-cartel', name: 'Glass Cartel', descriptor: 'Opportunists trading in recovered high-tech relics.' }
  ];

  const WORLD_TABLES = {
    biomes: ['storm-fens', 'salt-steppe', 'ember-canyon', 'ghostwood', 'shatterplain', 'mirror-lake', 'ash-vale'],
    landmarks: ['collapsed observatory', 'sunken relay tower', 'fractured basilica', 'hydro-forge ruins', 'glass orchard', 'warding monolith', 'buried station'],
    weather: ['clear wind', 'fog banks', 'acid drizzle', 'dust storm', 'dry heat', 'cold front', 'electric squall'],
    factionRisks: ['low', 'moderate', 'high']
  };

  const Chronicle = {
    timers: [],
    state: null,
    uiMounted: false,
    lastRenderHash: '',
    commandEchoGuard: false,
    bootedAt: new Date().toISOString(),
    eventHandlersRegistered: false
  };

  function ensureObjects() {
    oc.character.customData ??= {};
    oc.character.customData.PUBLIC ??= {};
    oc.thread.customData ??= {};
  }

  function safeClone(value, fallback = null) {
    try {
      return JSON.parse(JSON.stringify(value));
    } catch (_err) {
      return fallback;
    }
  }

  function hashString(input) {
    let h = 2166136261;
    const text = String(input || '');
    for (let i = 0; i < text.length; i++) {
      h ^= text.charCodeAt(i);
      h = Math.imul(h, 16777619);
    }
    return h >>> 0;
  }

  function rngFromSeed(seed) {
    let a = hashString(seed);
    return function rand() {
      a += 0x6D2B79F5;
      let t = a;
      t = Math.imul(t ^ (t >>> 15), t | 1);
      t ^= t + Math.imul(t ^ (t >>> 7), t | 61);
      return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
    };
  }

  function pick(rand, list) {
    if (!list || !list.length) return null;
    return list[Math.floor(rand() * list.length) % list.length];
  }

  function clamp(value, min, max) {
    return Math.max(min, Math.min(max, value));
  }

  function nowIso() {
    return new Date().toISOString();
  }

  function dayPhase(hour) {
    if (hour < 5) return 'deep-night';
    if (hour < 8) return 'dawn';
    if (hour < 12) return 'morning';
    if (hour < 17) return 'afternoon';
    if (hour < 20) return 'dusk';
    return 'night';
  }

  function safeString(value) {
    return String(value == null ? '' : value);
  }

  function htmlEscape(value) {
    return safeString(value)
      .replaceAll('&', '&amp;')
      .replaceAll('<', '&lt;')
      .replaceAll('>', '&gt;')
      .replaceAll('"', '&quot;')
      .replaceAll("'", '&#39;');
  }

  function makeFactionState(rand) {
    const state = {};
    for (const faction of FACTIONS) {
      state[faction.id] = {
        id: faction.id,
        name: faction.name,
        descriptor: faction.descriptor,
        reputation: clamp(Math.floor(rand() * 41) - 15, -100, 100),
        riskLevel: pick(rand, WORLD_TABLES.factionRisks),
        opportunities: [],
        recentConsequences: [],
        leverage: clamp(Math.floor(rand() * 100), 0, 100)
      };
    }
    return state;
  }

  function createWorld(seed) {
    const rand = rngFromSeed(seed + '|world');
    const regionCount = 12;
    const regions = [];

    for (let i = 0; i < regionCount; i++) {
      const id = `rg-${i + 1}`;
      const biome = pick(rand, WORLD_TABLES.biomes);
      const danger = clamp(Math.floor(rand() * 5) + 1, 1, 5);
      const localResources = [pick(rand, ['food', 'water', 'medicine', 'salvage']), pick(rand, ['food', 'water', 'medicine', 'salvage', 'fuelCells'])]
        .filter((v, idx, arr) => arr.indexOf(v) === idx);

      const influence = {};
      for (const f of FACTIONS) {
        influence[f.id] = clamp(Math.floor(rand() * 121) - 60 + danger * 5, -100, 100);
      }

      regions.push({
        id,
        name: `Region ${i + 1}`,
        biome,
        danger,
        biomeTags: [
          biome,
          pick(rand, ['fog-heavy', 'wind-cut', 'ruin-dense', 'predator-lanes', 'fertile-pockets', 'radiant-echoes'])
        ],
        notableLandmarks: [pick(rand, WORLD_TABLES.landmarks), pick(rand, WORLD_TABLES.landmarks)]
          .filter((v, idx, arr) => arr.indexOf(v) === idx),
        localResources,
        factionInfluence: influence,
        encounterPools: {
          travel: ['weather-front', 'hostile-contact', 'discovery', 'resource-windfall', 'faction-encounter', 'contract-lead'],
          camp: ['camp-reflection', 'crew-conflict', 'faction-encounter', 'disease-risk', 'resource-windfall']
        },
        loreHooks: [
          `Recovered maps reference a pre-collapse transit nexus beneath this ${biome}.`,
          `Locals claim ${pick(rand, WORLD_TABLES.landmarks)} still broadcasts dormant coordinates.`
        ],
        neighbors: []
      });
    }

    for (let i = 0; i < regions.length; i++) {
      const n1 = (i + 1) % regions.length;
      const n2 = (i + 2) % regions.length;
      const n3 = (i + 5) % regions.length;
      const prev = (i - 1 + regions.length) % regions.length;
      regions[i].neighbors = [regions[n1].id, regions[n2].id, regions[n3].id, regions[prev].id]
        .filter((v, idx, arr) => arr.indexOf(v) === idx);
    }

    return {
      seed,
      regions,
      discoveredRegions: [regions[0].id],
      currentLocation: regions[0].id,
      routeHistory: [regions[0].id],
      weather: {
        current: pick(rand, WORLD_TABLES.weather),
        severity: clamp(Math.floor(rand() * 3) + 1, 1, 5),
        pressure: 'stable'
      },
      environment: {
        hazardLevel: 2,
        visibility: 'clear',
        anomalyDrift: 14
      }
    };
  }

  function createParty(seed) {
    const rand = rngFromSeed(seed + '|party');
    const names = ['Mara Quell', 'Iven Drax', 'Sera Vale', 'Torin Ash', 'Nyra Holt', 'Kade Mercer', 'Orrin Pike', 'Rhea Sol'];
    const roles = ['Pathfinder', 'Quartermaster', 'Medic', 'Surveyor', 'Engineer', 'Scout'];
    const traits = ['disciplined', 'superstitious', 'resilient', 'calculating', 'idealistic', 'stoic', 'reckless'];

    const roster = Array.from({ length: 5 }).map((_, idx) => ({
      id: `pm-${idx + 1}`,
      name: pick(rand, names) + (idx > 0 ? `-${idx + 1}` : ''),
      role: pick(rand, roles),
      traits: [pick(rand, traits), pick(rand, traits)].filter((v, i, arr) => arr.indexOf(v) === i),
      morale: clamp(58 + Math.floor(rand() * 35), 0, 100),
      fatigue: clamp(9 + Math.floor(rand() * 25), 0, 100),
      conditions: [],
      utility: {
        scouting: clamp(30 + Math.floor(rand() * 70), 1, 100),
        medicine: clamp(20 + Math.floor(rand() * 70), 1, 100),
        engineering: clamp(20 + Math.floor(rand() * 70), 1, 100),
        diplomacy: clamp(20 + Math.floor(rand() * 70), 1, 100)
      },
      relationships: {}
    }));

    for (const a of roster) {
      for (const b of roster) {
        if (a.id === b.id) continue;
        a.relationships[b.id] = clamp(Math.floor(rand() * 61) - 30, -100, 100);
      }
    }

    return {
      roster,
      reserves: [],
      moraleAverage: 0,
      frictionIndex: 0,
      synergyIndex: 0
    };
  }

  function createContracts(seed, regions) {
    const rand = rngFromSeed(seed + '|contracts');
    const regionById = Object.fromEntries((regions || []).map((r) => [r.id, r]));

    const specs = [
      {
        id: 'ct-1',
        title: 'Reopen the River Relay',
        issuerFaction: 'river-compact',
        type: 'recovery',
        regionId: regions[2]?.id || regions[0]?.id,
        steps: [
          { id: 'ct-1-s1', text: 'Survey relay foundations', done: false },
          { id: 'ct-1-s2', text: 'Secure conductor coils', done: false },
          { id: 'ct-1-s3', text: 'Recalibrate relay beacon', done: false }
        ],
        rewards: { resources: { food: 14, water: 22, salvage: 18 }, reputation: { 'river-compact': 9 } },
        failureConsequences: { reputation: { 'river-compact': -10, 'ironwardens': -4 }, morale: -6 },
        branching: {
          riskPath: 'Divert power from unstable ward pylons for faster completion.',
          safePath: 'Negotiate sanctioned channel access with slower timeline.'
        },
        status: 'active',
        deadlineDay: 8
      },
      {
        id: 'ct-2',
        title: 'Ashen Ledger Retrieval',
        issuerFaction: 'embersynod',
        type: 'lore',
        regionId: regions[4]?.id || regions[0]?.id,
        steps: [
          { id: 'ct-2-s1', text: 'Locate the archive chamber', done: false },
          { id: 'ct-2-s2', text: 'Bypass ward signatures', done: false },
          { id: 'ct-2-s3', text: 'Return ledger intact', done: false }
        ],
        rewards: { resources: { medicine: 10, salvage: 20 }, reputation: { embersynod: 10 }, codexEntry: 'ashen-ledger-protocol' },
        failureConsequences: { reputation: { embersynod: -12, 'verdant-covenant': -5 }, morale: -5 },
        branching: {
          riskPath: 'Break the ward lattice and absorb corruption risk.',
          safePath: 'Decode ward phrases with Synod emissaries.'
        },
        status: 'available',
        deadlineDay: 11
      },
      {
        id: 'ct-3',
        title: 'Wardens Supply Arbitration',
        issuerFaction: 'ironwardens',
        type: 'diplomacy',
        regionId: regions[6]?.id || regions[0]?.id,
        steps: [
          { id: 'ct-3-s1', text: 'Escort supply convoy through contested route', done: false },
          { id: 'ct-3-s2', text: 'Resolve checkpoint dispute', done: false }
        ],
        rewards: { resources: { food: 20, fuelCells: 12 }, reputation: { ironwardens: 8 } },
        failureConsequences: { reputation: { ironwardens: -14, 'river-compact': -6 }, morale: -4 },
        branching: {
          riskPath: 'Force passage through disputed route.',
          safePath: 'Broker temporary truce with route fees.'
        },
        status: 'available',
        deadlineDay: 14
      }
    ];

    for (const c of specs) {
      c.progress = 0;
      c.regionName = regionById[c.regionId]?.name || c.regionId;
      c.consequenceTrail = [];
    }

    return {
      active: specs.filter((c) => c.status === 'active'),
      available: specs.filter((c) => c.status === 'available'),
      completed: [],
      failed: []
    };
  }

  function defaultState(seedHint) {
    const seed = seedHint || `cf-${Date.now()}`;
    const world = createWorld(seed);
    const party = createParty(seed);

    return {
      schemaVersion: SCHEMA_VERSION,
      expedition: {
        id: `exp-${Date.now()}`,
        name: 'Chronicle Foundry Expedition',
        commander: 'Field Commander',
        status: 'active',
        createdAt: nowIso(),
        notes: '',
        stressTestProfile: true
      },
      ui: {
        screen: CONFIG.ui.defaultScreen,
        iframeOpen: false,
        tutorialDismissed: false,
        onboardingStep: 0,
        showDebugByDefault: false,
        selectedContractId: null,
        selectedPartyMemberId: null
      },
      world,
      time: {
        day: 1,
        hour: 7,
        turn: 0,
        phase: dayPhase(7),
        totalHoursElapsed: 0
      },
      weatherHistory: [],
      party,
      resources: {
        weightCapacity: 220,
        categories: {
          essentials: { food: 120, water: 126, medicine: 30 },
          materials: { salvage: 50, fuelCells: 24 },
          special: { relicShards: 0, signalKeys: 1 }
        },
        equipment: [
          { id: 'eq-1', name: 'Survey Drone Mk.II', assignedTo: party.roster[0]?.id || null, utility: 'scouting', condition: 80, weight: 12 },
          { id: 'eq-2', name: 'Portable Medbench', assignedTo: party.roster[2]?.id || null, utility: 'medicine', condition: 84, weight: 16 },
          { id: 'eq-3', name: 'Arc-Spike Kit', assignedTo: party.roster[3]?.id || null, utility: 'engineering', condition: 66, weight: 14 },
          { id: 'eq-4', name: 'Signal Lattice Array', assignedTo: party.roster[1]?.id || null, utility: 'diplomacy', condition: 70, weight: 10 }
        ],
        consumables: {
          rationRatePerTurn: 3,
          waterRatePerTurn: 3,
          medicineUseChance: 0.2
        }
      },
      factions: makeFactionState(rngFromSeed(seed + '|factions')),
      contracts: createContracts(seed, world.regions),
      codex: {
        entries: [
          { id: 'frontier-charter', title: 'Frontier Charter', body: 'Expedition authority is provisional and contingent on delivered outcomes.', unlockedAt: nowIso() },
          { id: 'foundry-protocol', title: 'Foundry Protocol', body: 'All command actions must reconcile narrative coherence with measurable expedition state.', unlockedAt: nowIso() }
        ],
        discoveries: []
      },
      scene: {
        type: 'onboarding',
        summary: 'Engine boot and operational calibration.',
        promptFrame: 'Baseline readiness checks complete.',
        continuityTags: ['boot', 'frontier', 'expedition']
      },
      events: {
        history: [],
        cooldowns: {},
        lastResolved: null,
        encounterCount: 0
      },
      notifications: [],
      snapshots: [],
      saveState: {
        lastSavedAt: nowIso(),
        lastLoadedAt: nowIso(),
        totalSaves: 0,
        totalRestores: 0
      },
      imagePipeline: {
        lastPrompt: '',
        queue: [],
        presets: {
          expedition: 'wide-angle expedition documentation, practical gear, weathered textiles',
          landmark: 'architectural focus, environmental scale, grounded realism',
          factionPortrait: 'frontier faction portrait, insignia detail, practical attire',
          event: 'dynamic field incident, environmental pressure, cinematic documentary style'
        },
        history: []
      },
      debug: {
        enabled: false,
        diagnostics: [],
        safetyFlags: {
          malformedRecoveries: 0,
          duplicateListenerBlocked: false,
          timerCleanupCount: 0,
          invalidActionBlocked: 0,
          recoveries: []
        },
        commandTrace: []
      }
    };
  }

  function migrateState(state) {
    if (!state || typeof state !== 'object') return null;
    let s = state;
    s.schemaVersion ??= 0;

    if (s.schemaVersion < 1) {
      s.notifications ??= [];
      s.debug ??= { enabled: false, diagnostics: [], safetyFlags: { malformedRecoveries: 0, duplicateListenerBlocked: false, timerCleanupCount: 0, invalidActionBlocked: 0, recoveries: [] }, commandTrace: [] };
      s.schemaVersion = 1;
    }

    if (s.schemaVersion < 2) {
      s.imagePipeline ??= { lastPrompt: '', queue: [], presets: { expedition: 'expedition documentary', landmark: 'landmark survey', factionPortrait: 'faction portrait', event: 'field incident' }, history: [] };
      s.saveState ??= { lastSavedAt: nowIso(), lastLoadedAt: nowIso(), totalSaves: 0, totalRestores: 0 };
      s.schemaVersion = 2;
    }

    if (s.schemaVersion < 3) {
      s.ui ??= { screen: CONFIG.ui.defaultScreen, iframeOpen: false, tutorialDismissed: false, onboardingStep: 0, showDebugByDefault: false, selectedContractId: null, selectedPartyMemberId: null };
      s.weatherHistory ??= [];
      s.events ??= { history: [], cooldowns: {}, lastResolved: null, encounterCount: 0 };
      s.schemaVersion = 3;
    }

    s.schemaVersion = SCHEMA_VERSION;
    return s;
  }

  function validateStateShape(state) {
    if (!state || typeof state !== 'object') return false;
    if (!state.world || !Array.isArray(state.world.regions)) return false;
    if (!state.party || !Array.isArray(state.party.roster)) return false;
    if (!state.resources || !state.resources.categories) return false;
    if (!state.factions || typeof state.factions !== 'object') return false;
    if (!state.contracts || !Array.isArray(state.contracts.active)) return false;
    return true;
  }

  function withRecovery(action, contextLabel) {
    try {
      return action();
    } catch (err) {
      Chronicle.state.debug.safetyFlags.recoveries.push({ at: nowIso(), context: contextLabel, error: safeString(err && err.message || err) });
      Chronicle.state.debug.safetyFlags.recoveries = Chronicle.state.debug.safetyFlags.recoveries.slice(-50);
      Chronicle.state.debug.safetyFlags.malformedRecoveries += 1;
      enqueueNotification('error', `Recovery path triggered: ${contextLabel}`);
      return null;
    }
  }

  function loadState() {
    ensureObjects();
    const candidates = [
      oc.thread.customData[NS],
      oc.character.customData[NS],
      oc.character.customData.PUBLIC[STORAGE_KEY]
    ];

    for (const cand of candidates) {
      if (!cand) continue;
      const cloned = safeClone(cand, null);
      if (!cloned) continue;
      const migrated = migrateState(cloned);
      if (!validateStateShape(migrated)) continue;
      migrated.saveState ??= { lastSavedAt: nowIso(), lastLoadedAt: nowIso(), totalSaves: 0, totalRestores: 0 };
      migrated.saveState.lastLoadedAt = nowIso();
      return migrated;
    }

    const created = defaultState();
    created.debug.safetyFlags.malformedRecoveries += 1;
    return created;
  }

  function saveState() {
    ensureObjects();
    const serial = safeClone(Chronicle.state, null);
    if (!serial) return;
    serial.saveState.lastSavedAt = nowIso();
    serial.saveState.totalSaves = (serial.saveState.totalSaves || 0) + 1;
    oc.thread.customData[NS] = serial;
    oc.character.customData[NS] = serial;
    oc.character.customData.PUBLIC[STORAGE_KEY] = serial;
    Chronicle.state = serial;
  }

  function registerTimer(id) {
    Chronicle.timers.push(id);
    window.__pcbw_cf_timers ??= [];
    window.__pcbw_cf_timers.push(id);
  }

  function cleanupTimers() {
    const all = [];
    if (Array.isArray(window.__pcbw_cf_timers)) {
      all.push(...window.__pcbw_cf_timers);
      window.__pcbw_cf_timers = [];
    }
    all.push(...Chronicle.timers);
    Chronicle.timers = [];
    let cleaned = 0;
    for (const id of all) {
      clearInterval(id);
      clearTimeout(id);
      cleaned++;
    }
    if (Chronicle.state && Chronicle.state.debug && Chronicle.state.debug.safetyFlags) {
      Chronicle.state.debug.safetyFlags.timerCleanupCount += cleaned;
    }
  }

  function getRegionById(regionId) {
    return (Chronicle.state.world.regions || []).find((r) => r.id === regionId) || null;
  }

  function currentRegion() {
    return getRegionById(Chronicle.state.world.currentLocation);
  }

  function enqueueNotification(level, text) {
    Chronicle.state.notifications.push({
      id: `ntf-${Date.now()}-${Math.floor(Math.random() * 9999)}`,
      level,
      text,
      at: nowIso(),
      seen: false
    });
    if (Chronicle.state.notifications.length > MAX_NOTIFICATIONS) {
      Chronicle.state.notifications = Chronicle.state.notifications.slice(Chronicle.state.notifications.length - MAX_NOTIFICATIONS);
    }
  }

  function consumeNotificationsForToast(limit = 3) {
    const unseen = Chronicle.state.notifications.filter((n) => !n.seen).slice(0, limit);
    for (const n of unseen) n.seen = true;
    return unseen;
  }

  function logEvent(type, details) {
    Chronicle.state.events.history.push({
      id: `evt-${Date.now()}-${Math.floor(Math.random() * 9999)}`,
      turn: Chronicle.state.time.turn,
      day: Chronicle.state.time.day,
      hour: Chronicle.state.time.hour,
      type,
      details,
      at: nowIso()
    });
    if (Chronicle.state.events.history.length > MAX_EVENT_HISTORY) {
      Chronicle.state.events.history = Chronicle.state.events.history.slice(Chronicle.state.events.history.length - MAX_EVENT_HISTORY);
    }
  }

  function recomputePartyIndices() {
    const roster = Chronicle.state.party.roster || [];
    if (!roster.length) {
      Chronicle.state.party.moraleAverage = 0;
      Chronicle.state.party.frictionIndex = 0;
      Chronicle.state.party.synergyIndex = 0;
      return;
    }

    Chronicle.state.party.moraleAverage = Math.round(roster.reduce((sum, p) => sum + (p.morale || 0), 0) / roster.length);

    const rel = [];
    for (const member of roster) {
      for (const key of Object.keys(member.relationships || {})) rel.push(member.relationships[key]);
    }
    const relAvg = rel.length ? rel.reduce((a, b) => a + b, 0) / rel.length : 0;
    Chronicle.state.party.frictionIndex = Math.round(clamp(-relAvg + 20, 0, 100));
    Chronicle.state.party.synergyIndex = Math.round(clamp(relAvg + 50, 0, 100));
  }

  function inventoryWeight() {
    const c = Chronicle.state.resources.categories;
    const by = CONFIG.resources.weightByCategory;
    let total = 0;
    total += c.essentials.food * by.food;
    total += c.essentials.water * by.water;
    total += c.essentials.medicine * by.medicine;
    total += c.materials.salvage * by.salvage;
    total += c.materials.fuelCells * by.fuelCells;
    total += c.special.relicShards * by.relicShards;
    total += c.special.signalKeys * by.signalKeys;
    for (const eq of Chronicle.state.resources.equipment) total += Number(eq.weight || 0);
    return Math.round(total * 10) / 10;
  }

  function mutateResource(path, delta, min = 0, max = null) {
    const parts = path.split('.');
    let target = Chronicle.state.resources.categories;
    for (let i = 0; i < parts.length - 1; i++) target = target[parts[i]];
    const key = parts[parts.length - 1];
    const cap = max == null ? CONFIG.resources.caps[key] ?? 9999 : max;
    target[key] = clamp((target[key] || 0) + delta, min, cap);
  }

  function adjustFactionReputation(factionId, delta, reason) {
    const faction = Chronicle.state.factions[factionId];
    if (!faction) return;
    faction.reputation = clamp((faction.reputation || 0) + delta, -100, 100);
    faction.recentConsequences.push({ at: nowIso(), delta, reason });
    faction.recentConsequences = faction.recentConsequences.slice(-30);
    if (Math.abs(delta) >= 6) {
      enqueueNotification(delta > 0 ? 'success' : 'warning', `${faction.name} standing ${delta > 0 ? 'improved' : 'dropped'} by ${Math.abs(delta)}.`);
    }
  }

  function updateRelationshipsAfterTurn(mode) {
    const roster = Chronicle.state.party.roster;
    for (let i = 0; i < roster.length; i++) {
      for (let j = i + 1; j < roster.length; j++) {
        const a = roster[i];
        const b = roster[j];
        const keyA = b.id;
        const keyB = a.id;
        const weatherPenalty = Chronicle.state.world.weather.severity >= CONFIG.simulation.severeWeatherThreshold ? -1 : 0;
        const fatiguePenalty = (a.fatigue + b.fatigue) > 145 ? -2 : 0;
        const campBonus = mode === 'camp' ? 2 : 0;
        const sharedRiskBonus = mode === 'travel' && Chronicle.state.events.lastResolved && String(Chronicle.state.events.lastResolved.eventId || '').includes('hostile') ? 1 : 0;
        const delta = clamp(campBonus + sharedRiskBonus + weatherPenalty + fatiguePenalty, -3, 3);
        a.relationships[keyA] = clamp((a.relationships[keyA] || 0) + delta, -100, 100);
        b.relationships[keyB] = clamp((b.relationships[keyB] || 0) + delta, -100, 100);
      }
    }
  }

  function updateWeatherForTurn() {
    const roll = Math.random();
    const weather = Chronicle.state.world.weather;
    if (roll < 0.4) {
      weather.current = pick(rngFromSeed(`${Chronicle.state.world.seed}|w|${Chronicle.state.time.turn}`), WORLD_TABLES.weather);
      weather.severity = clamp(weather.severity + (Math.random() < 0.45 ? -1 : 1), 1, 5);
      weather.pressure = weather.severity >= 4 ? 'volatile' : (weather.severity <= 2 ? 'stable' : 'shifting');
      Chronicle.state.weatherHistory.push({ turn: Chronicle.state.time.turn, weather: weather.current, severity: weather.severity, at: nowIso() });
      Chronicle.state.weatherHistory = Chronicle.state.weatherHistory.slice(-90);
    }
  }

  function advanceTime(hours, mode) {
    const time = Chronicle.state.time;
    const before = { day: time.day, hour: time.hour, phase: time.phase };
    time.totalHoursElapsed += hours;
    time.hour += hours;
    while (time.hour >= 24) {
      time.hour -= 24;
      time.day += 1;
    }
    time.turn += 1;
    time.phase = dayPhase(time.hour);

    mutateResource('essentials.food', -Math.max(1, Math.round(Chronicle.state.resources.consumables.rationRatePerTurn * (hours / CONFIG.simulation.campHours))));
    mutateResource('essentials.water', -Math.max(1, Math.round(Chronicle.state.resources.consumables.waterRatePerTurn * (hours / CONFIG.simulation.campHours))));

    for (const member of Chronicle.state.party.roster) {
      const weatherStrain = Chronicle.state.world.weather.severity >= CONFIG.simulation.severeWeatherThreshold ? 2 : 0;
      if (mode === 'travel') {
        member.fatigue = clamp(member.fatigue + 8 + weatherStrain, 0, 100);
        member.morale = clamp(member.morale - (weatherStrain > 0 ? 3 : 1), 0, 100);
      } else {
        member.fatigue = clamp(member.fatigue - 11, 0, 100);
        member.morale = clamp(member.morale + 3, 0, 100);
      }

      member.conditions = member.conditions || [];
      if (member.fatigue > CONFIG.simulation.fatigueWarning && member.conditions.indexOf('exhausted') === -1) member.conditions.push('exhausted');
      if (member.fatigue < 64) member.conditions = member.conditions.filter((c) => c !== 'exhausted');
      if (Math.random() < 0.12 && mode === 'travel' && Chronicle.state.resources.categories.essentials.medicine <= CONFIG.simulation.lowMedicineWarning) {
        if (member.conditions.indexOf('strained') === -1) member.conditions.push('strained');
      }
    }

    updateWeatherForTurn();
    updateRelationshipsAfterTurn(mode);
    recomputePartyIndices();
    checkResourceWarnings();

    logEvent('turn-advance', {
      mode,
      hours,
      from: before,
      to: { day: time.day, hour: time.hour, phase: time.phase },
      weather: safeClone(Chronicle.state.world.weather, {})
    });
  }

  function checkResourceWarnings() {
    const e = Chronicle.state.resources.categories.essentials;
    if (e.food <= CONFIG.simulation.lowFoodWarning) enqueueNotification('warning', 'Food reserves critical. Consider foraging or contract payout routes.');
    if (e.water <= CONFIG.simulation.lowWaterWarning) enqueueNotification('warning', 'Water reserves critical. Route to freshwater zones recommended.');
    if (e.medicine <= CONFIG.simulation.lowMedicineWarning) enqueueNotification('warning', 'Medicine reserves nearly exhausted. Injury risk increased.');
    if (inventoryWeight() > Chronicle.state.resources.weightCapacity) enqueueNotification('warning', 'Loadout exceeds weight capacity. Travel penalties active.');
  }

  function weightedEvent(mode) {
    const region = currentRegion();
    if (!region) return null;

    const pools = mode === 'camp' ? region.encounterPools.camp : region.encounterPools.travel;
    const candidates = [];

    for (const eventId of pools) {
      const cooldown = Chronicle.state.events.cooldowns[eventId] || -1;
      if (cooldown > Chronicle.state.time.turn) continue;

      let weight = 10;
      if (eventId === 'weather-front') weight = CONFIG.eventWeights.weatherFront + Chronicle.state.world.weather.severity * 2;
      if (eventId === 'hostile-contact') weight = CONFIG.eventWeights.hostileContact + region.danger * 3;
      if (eventId === 'discovery') weight = CONFIG.eventWeights.discovery + (Chronicle.state.world.discoveredRegions.includes(region.id) ? 0 : 6);
      if (eventId === 'faction-encounter') weight = CONFIG.eventWeights.factionEncounter + Math.floor(Math.random() * 4);
      if (eventId === 'resource-windfall') weight = CONFIG.eventWeights.resourceWindfall + (Chronicle.state.resources.categories.essentials.food < 30 ? 4 : 0);
      if (eventId === 'crew-conflict') weight = CONFIG.eventWeights.crewConflict + Math.round(Chronicle.state.party.frictionIndex / 8);
      if (eventId === 'contract-lead') weight = CONFIG.eventWeights.contractLead + (Chronicle.state.contracts.active.length ? 4 : 0);
      if (eventId === 'disease-risk') weight = CONFIG.eventWeights.diseaseRisk + (Chronicle.state.resources.categories.essentials.medicine < 10 ? 5 : 0);
      if (eventId === 'camp-reflection') weight = CONFIG.eventWeights.campReflection + 2;

      candidates.push({ eventId, weight });
    }

    if (!candidates.length) return null;

    const total = candidates.reduce((sum, c) => sum + c.weight, 0);
    let roll = Math.random() * total;
    let choice = candidates[candidates.length - 1].eventId;
    for (const c of candidates) {
      roll -= c.weight;
      if (roll <= 0) {
        choice = c.eventId;
        break;
      }
    }

    Chronicle.state.events.cooldowns[choice] = Chronicle.state.time.turn + EVENT_COOLDOWN_TURNS;
    return choice;
  }

  function resolveEvent(mode) {
    const eventId = weightedEvent(mode);
    if (!eventId) return null;

    const region = currentRegion();
    let outcome = '';

    if (eventId === 'weather-front') {
      Chronicle.state.world.weather.severity = clamp(Chronicle.state.world.weather.severity + 1, 1, 5);
      Chronicle.state.world.environment.visibility = Chronicle.state.world.weather.severity >= 4 ? 'obscured' : 'reduced';
      mutateResource('materials.fuelCells', -2, 0);
      outcome = 'Severe weather front reduced visibility and increased route strain.';
      enqueueNotification('warning', 'Weather front intensified. Travel risk increased.');
    } else if (eventId === 'hostile-contact') {
      mutateResource('essentials.medicine', -1, 0);
      for (const m of Chronicle.state.party.roster) {
        if (Math.random() < 0.24) {
          m.conditions = m.conditions || [];
          if (m.conditions.indexOf('injured') === -1) m.conditions.push('injured');
          m.morale = clamp(m.morale - 5, 0, 100);
        }
      }
      adjustFactionReputation('ironwardens', -2, 'Security lapse during hostile contact.');
      outcome = 'Hostile contact forced evasive maneuvering and minor casualties.';
      enqueueNotification('warning', 'Hostile contact resolved. Injury checks recommended.');
    } else if (eventId === 'discovery') {
      const landmark = pick(rngFromSeed(`${Chronicle.state.world.seed}|disc|${Chronicle.state.time.turn}`), region.notableLandmarks || ['unidentified ruin']);
      Chronicle.state.codex.discoveries.push({
        id: `disc-${Date.now()}`,
        title: landmark,
        regionId: region.id,
        body: `Survey indicates strategic relevance near ${region.name}.`,
        at: nowIso()
      });
      Chronicle.state.codex.discoveries = Chronicle.state.codex.discoveries.slice(-MAX_DISCOVERIES);
      mutateResource('materials.salvage', 6, 0);
      outcome = `Discovery catalogued: ${landmark}.`;
      enqueueNotification('success', `Discovery in ${region.name}: ${landmark}`);
    } else if (eventId === 'faction-encounter') {
      const faction = pick(rngFromSeed(`${Chronicle.state.world.seed}|faction|${Chronicle.state.time.turn}`), Object.values(Chronicle.state.factions));
      const delta = Math.random() < 0.5 ? 4 : -3;
      adjustFactionReputation(faction.id, delta, 'Field encounter negotiation outcome.');
      mutateResource('materials.salvage', delta > 0 ? 3 : -2, 0);
      outcome = `${faction.name} field encounter ${delta > 0 ? 'improved' : 'strained'} standing.`;
    } else if (eventId === 'resource-windfall') {
      mutateResource('essentials.food', 8, 0);
      mutateResource('essentials.water', 10, 0);
      mutateResource('materials.salvage', 4, 0);
      outcome = 'Unexpected resource cache recovered.';
      enqueueNotification('success', 'Resource windfall recovered from frontier cache.');
    } else if (eventId === 'crew-conflict') {
      for (const m of Chronicle.state.party.roster) m.morale = clamp(m.morale - 2, 0, 100);
      updateRelationshipsAfterTurn('travel');
      outcome = 'Crew conflict reduced cohesion; mediation required.';
      enqueueNotification('warning', 'Party friction increased after camp dispute.');
    } else if (eventId === 'contract-lead') {
      const candidate = Chronicle.state.contracts.available[0];
      if (candidate) {
        enqueueNotification('info', `Contract lead strengthened: ${candidate.title}`);
      }
      outcome = 'New intelligence refined contract opportunities.';
    } else if (eventId === 'disease-risk') {
      const target = Chronicle.state.party.roster[Math.floor(Math.random() * Chronicle.state.party.roster.length)];
      if (target) {
        target.conditions = target.conditions || [];
        if (target.conditions.indexOf('ill') === -1) target.conditions.push('ill');
        target.morale = clamp(target.morale - 4, 0, 100);
      }
      mutateResource('essentials.medicine', -1, 0);
      outcome = 'Camp sanitation breach introduced illness risk.';
      enqueueNotification('warning', 'Illness risk detected. Medicine reserves consumed.');
    } else if (eventId === 'camp-reflection') {
      for (const m of Chronicle.state.party.roster) m.morale = clamp(m.morale + 2, 0, 100);
      outcome = 'Camp reflection improved morale and planning alignment.';
    }

    Chronicle.state.events.encounterCount += 1;
    Chronicle.state.events.lastResolved = { eventId, regionId: region.id, mode, outcome, at: nowIso() };
    logEvent('event', Chronicle.state.events.lastResolved);
    return Chronicle.state.events.lastResolved;
  }

  function listConnectedRegions() {
    const region = currentRegion();
    if (!region) return [];
    return region.neighbors.map((id) => getRegionById(id)).filter(Boolean);
  }

  function travelTo(regionId) {
    const fromRegion = currentRegion();
    const destination = getRegionById(regionId);
    if (!destination) {
      Chronicle.state.debug.safetyFlags.invalidActionBlocked += 1;
      return { ok: false, error: `Unknown region: ${regionId}` };
    }

    if (!fromRegion || fromRegion.neighbors.indexOf(destination.id) === -1) {
      Chronicle.state.debug.safetyFlags.invalidActionBlocked += 1;
      return { ok: false, error: `Region ${destination.id} is not directly connected.` };
    }

    if (inventoryWeight() > Chronicle.state.resources.weightCapacity + 30) {
      Chronicle.state.debug.safetyFlags.invalidActionBlocked += 1;
      return { ok: false, error: 'Travel blocked: overload exceeds safety threshold. Rebalance inventory.' };
    }

    Chronicle.state.world.currentLocation = destination.id;
    Chronicle.state.world.routeHistory.push(destination.id);
    Chronicle.state.world.routeHistory = Chronicle.state.world.routeHistory.slice(-160);
    if (Chronicle.state.world.discoveredRegions.indexOf(destination.id) === -1) Chronicle.state.world.discoveredRegions.push(destination.id);

    advanceTime(CONFIG.simulation.travelHours, 'travel');
    const event = resolveEvent('travel');
    updateContractsAfterTurn();

    Chronicle.state.scene = {
      type: 'travel-hardship',
      summary: `Transit completed from ${fromRegion ? fromRegion.name : 'unknown'} to ${destination.name}.`,
      promptFrame: event ? `${event.eventId}: ${event.outcome}` : 'No major event.',
      continuityTags: ['travel', destination.biome, `danger-${destination.danger}`, Chronicle.state.world.weather.current]
    };

    enqueueNotification('info', `Arrived at ${destination.name}.`);
    logEvent('travel', { from: fromRegion?.id || null, to: destination.id, eventId: event?.eventId || null });
    return { ok: true, event };
  }

  function campTurn() {
    advanceTime(CONFIG.simulation.campHours, 'camp');
    const event = resolveEvent('camp');
    updateContractsAfterTurn();

    Chronicle.state.scene = {
      type: 'camp-reflection',
      summary: 'Camp turn resolved with maintenance and morale adjustments.',
      promptFrame: event ? `${event.eventId}: ${event.outcome}` : 'Camp remained stable.',
      continuityTags: ['camp', Chronicle.state.world.weather.current, Chronicle.state.time.phase]
    };

    logEvent('camp', { eventId: event?.eventId || null });
    return { ok: true, event };
  }

  function acceptContract(contractId) {
    const idx = Chronicle.state.contracts.available.findIndex((c) => c.id === contractId);
    if (idx < 0) return { ok: false, error: `Contract not available: ${contractId}` };
    const contract = Chronicle.state.contracts.available.splice(idx, 1)[0];
    contract.status = 'active';
    contract.progress = 0;
    Chronicle.state.contracts.active.push(contract);
    enqueueNotification('info', `Contract accepted: ${contract.title}`);
    logEvent('contract-accepted', { id: contract.id, title: contract.title });
    return { ok: true, contract };
  }

  function progressContract(contractId, pathChoice) {
    const contract = Chronicle.state.contracts.active.find((c) => c.id === contractId);
    if (!contract) return { ok: false, error: `Contract not active: ${contractId}` };

    const nextStep = contract.steps.find((s) => !s.done);
    if (!nextStep) return { ok: false, error: `Contract already complete: ${contractId}` };

    nextStep.done = true;
    contract.consequenceTrail = contract.consequenceTrail || [];
    contract.consequenceTrail.push({ at: nowIso(), step: nextStep.id, choice: pathChoice || 'standard' });

    if (pathChoice === 'risk') {
      adjustFactionReputation(contract.issuerFaction, 2, `Risk path advanced for ${contract.title}`);
      adjustFactionReputation('ironwardens', -1, `Risk path turbulence from ${contract.title}`);
      mutateResource('materials.salvage', 4, 0);
      enqueueNotification('warning', `Risk branch chosen for ${contract.title}. Potential instability raised.`);
    } else if (pathChoice === 'safe') {
      adjustFactionReputation(contract.issuerFaction, 1, `Safe path advanced for ${contract.title}`);
      mutateResource('materials.fuelCells', -1, 0);
      enqueueNotification('info', `Safe branch chosen for ${contract.title}. Progress slower but stable.`);
    }

    contract.progress = Math.round((contract.steps.filter((s) => s.done).length / contract.steps.length) * 100);
    logEvent('contract-progress', { id: contract.id, step: nextStep.id, choice: pathChoice || 'standard', progress: contract.progress });

    if (contract.progress >= 100) {
      completeContract(contract.id);
    }

    return { ok: true, contract };
  }

  function completeContract(contractId) {
    const idx = Chronicle.state.contracts.active.findIndex((c) => c.id === contractId);
    if (idx < 0) return { ok: false, error: `Contract not active: ${contractId}` };
    const contract = Chronicle.state.contracts.active.splice(idx, 1)[0];
    contract.status = 'completed';

    const rewards = contract.rewards || {};
    const rw = rewards.resources || {};
    if (rw.food) mutateResource('essentials.food', rw.food, 0);
    if (rw.water) mutateResource('essentials.water', rw.water, 0);
    if (rw.medicine) mutateResource('essentials.medicine', rw.medicine, 0);
    if (rw.salvage) mutateResource('materials.salvage', rw.salvage, 0);
    if (rw.fuelCells) mutateResource('materials.fuelCells', rw.fuelCells, 0);

    for (const [fid, delta] of Object.entries(rewards.reputation || {})) {
      adjustFactionReputation(fid, delta, `Contract reward: ${contract.title}`);
    }

    if (rewards.codexEntry) {
      Chronicle.state.codex.entries.push({
        id: rewards.codexEntry,
        title: `Contract Archive: ${contract.title}`,
        body: `Recovered material from ${contract.title} has been indexed for future strategic planning.`,
        unlockedAt: nowIso()
      });
    }

    Chronicle.state.contracts.completed.push(contract);
    enqueueNotification('success', `Contract completed: ${contract.title}`);
    logEvent('contract-complete', { id: contract.id, title: contract.title });
    return { ok: true, contract };
  }

  function failContract(contract) {
    contract.status = 'failed';
    Chronicle.state.contracts.failed.push(contract);
    for (const [fid, delta] of Object.entries(contract.failureConsequences?.reputation || {})) {
      adjustFactionReputation(fid, delta, `Contract failure: ${contract.title}`);
    }
    for (const member of Chronicle.state.party.roster) {
      member.morale = clamp(member.morale + Number(contract.failureConsequences?.morale || 0), 0, 100);
    }
    enqueueNotification('warning', `Contract failed: ${contract.title}`);
    logEvent('contract-fail', { id: contract.id, title: contract.title });
  }

  function updateContractsAfterTurn() {
    for (const contract of Chronicle.state.contracts.active.slice()) {
      contract.progress = Math.round((contract.steps.filter((s) => s.done).length / contract.steps.length) * 100);
      if (Chronicle.state.time.day > contract.deadlineDay && contract.status === 'active') {
        Chronicle.state.contracts.active = Chronicle.state.contracts.active.filter((c) => c.id !== contract.id);
        failContract(contract);
      }
    }
  }

  function assignEquipment(eqId, memberId) {
    const eq = Chronicle.state.resources.equipment.find((e) => e.id === eqId);
    const member = Chronicle.state.party.roster.find((m) => m.id === memberId);
    if (!eq) return { ok: false, error: `Equipment missing: ${eqId}` };
    if (!member) return { ok: false, error: `Member missing: ${memberId}` };

    eq.assignedTo = member.id;
    eq.condition = clamp(eq.condition - 1, 20, 100);
    enqueueNotification('info', `${eq.name} assigned to ${member.name}.`);
    logEvent('equipment-assigned', { eqId, memberId });
    return { ok: true };
  }

  function useConsumable(kind, amount) {
    const qty = clamp(Number(amount || 1), 1, 20);
    if (kind === 'food') mutateResource('essentials.food', -qty, 0);
    if (kind === 'water') mutateResource('essentials.water', -qty, 0);
    if (kind === 'medicine') {
      mutateResource('essentials.medicine', -qty, 0);
      let healed = 0;
      for (const member of Chronicle.state.party.roster) {
        if ((member.conditions || []).includes('injured') || (member.conditions || []).includes('ill')) {
          member.conditions = member.conditions.filter((c) => c !== 'injured' && c !== 'ill');
          member.morale = clamp(member.morale + 3, 0, 100);
          healed++;
          if (healed >= qty) break;
        }
      }
      enqueueNotification('info', `Medicine applied. ${healed} crew conditions improved.`);
    }

    logEvent('consumable-used', { kind, qty });
    return { ok: true };
  }

  function saveSnapshot(label) {
    const snap = {
      id: `snap-${Date.now()}`,
      label: label || `D${Chronicle.state.time.day}-T${Chronicle.state.time.turn}`,
      createdAt: nowIso(),
      payload: safeClone(Chronicle.state, null)
    };
    if (!snap.payload) return null;
    Chronicle.state.snapshots.push(snap);
    Chronicle.state.snapshots = Chronicle.state.snapshots.slice(-MAX_SNAPSHOTS);
    enqueueNotification('info', `Snapshot saved: ${snap.label}`);
    logEvent('snapshot-save', { id: snap.id, label: snap.label });
    return snap;
  }

  function restoreSnapshot(snapshotId) {
    const snap = Chronicle.state.snapshots.find((s) => s.id === snapshotId);
    if (!snap) return { ok: false, error: `Snapshot not found: ${snapshotId}` };

    const restored = safeClone(snap.payload, null);
    if (!restored || !validateStateShape(restored)) return { ok: false, error: `Snapshot corrupted: ${snapshotId}` };

    Chronicle.state = migrateState(restored);
    Chronicle.state.saveState.totalRestores = (Chronicle.state.saveState.totalRestores || 0) + 1;
    enqueueNotification('info', `Snapshot restored: ${snap.label}`);
    logEvent('snapshot-restore', { id: snap.id, label: snap.label });
    return { ok: true, snap };
  }

  function resetExpedition(seedHint) {
    Chronicle.state = defaultState(seedHint ? `cf-${seedHint}` : undefined);
    enqueueNotification('info', `New expedition initialized${seedHint ? ` (${seedHint})` : ''}.`);
    saveState();
    renderUI(true);
  }

  function sceneTemplate(type) {
    const region = currentRegion();
    const weather = Chronicle.state.world.weather;
    const map = {
      discovery: `Discovery Frame: emphasize ${region?.name || 'current region'} landmark acquisition and unknown risks.`,
      crisis: `Crisis Frame: stress immediate resource pressure, hazard escalation, and hard choices.`,
      negotiation: `Negotiation Frame: tie faction standings and leverage balances to outcomes.`,
      camp: `Camp Reflection Frame: emotional processing, maintenance tradeoffs, and next-day planning.`,
      travel: `Travel Hardship Frame: terrain hazards, attrition, and route logic under weather pressure.`,
      turnin: `Contract Turn-In Frame: summarize reward consequences and strategic ripple effects.`
    };
    return map[type] || `Operational Frame: region ${region?.name || '?'} with weather ${weather.current}.`;
  }

  function buildHiddenContext() {
    const s = Chronicle.state;
    const region = currentRegion();
    const essentials = s.resources.categories.essentials;
    const materials = s.resources.categories.materials;

    const members = s.party.roster
      .map((m) => `${m.name}/${m.role}: morale=${m.morale}, fatigue=${m.fatigue}, cond=[${(m.conditions || []).join(',') || 'none'}]`)
      .join(' | ');

    const contracts = s.contracts.active
      .map((c) => `${c.id}:${c.title}:${c.progress}% deadline D${c.deadlineDay}`)
      .join(' ; ') || 'none';

    const factions = Object.values(s.factions)
      .map((f) => `${f.name}:${f.reputation}`)
      .join(' | ');

    const discoveries = s.codex.discoveries.slice(-4).map((d) => d.title).join(', ') || 'none';

    return [
      '[Chronicle Foundry Runtime Context]',
      `Expedition=${s.expedition.name} Commander=${s.expedition.commander} Status=${s.expedition.status}`,
      `Time=Day ${s.time.day} Hour ${s.time.hour} Phase ${s.time.phase} Turn ${s.time.turn}`,
      `Location=${region?.name || s.world.currentLocation} Biome=${region?.biome || '?'} Danger=${region?.danger ?? '?'}`,
      `Weather=${s.world.weather.current} Severity=${s.world.weather.severity} Pressure=${s.world.weather.pressure} Visibility=${s.world.environment.visibility}`,
      `Resources=Food ${essentials.food}, Water ${essentials.water}, Medicine ${essentials.medicine}, Salvage ${materials.salvage}, FuelCells ${materials.fuelCells}`,
      `LoadWeight=${inventoryWeight()}/${s.resources.weightCapacity}`,
      `Party=${members}`,
      `Contracts=${contracts}`,
      `Factions=${factions}`,
      `Discoveries=${discoveries}`,
      `LastEvent=${s.events.lastResolved ? `${s.events.lastResolved.eventId}: ${s.events.lastResolved.outcome}` : 'none'}`,
      `SceneTemplate=${sceneTemplate(s.scene.type === 'travel-hardship' ? 'travel' : (s.scene.type === 'camp-reflection' ? 'camp' : 'discovery'))}`,
      'OutputPolicy=Start with SITREP then narrative consequence update, then actionable options. Keep operational coherence.'
    ].join('\n');
  }

  function preBakeImagePrompt(sceneType) {
    const region = currentRegion();
    const s = Chronicle.state;
    const factionTop = Object.values(s.factions).sort((a, b) => b.reputation - a.reputation)[0];
    const base = s.imagePipeline.presets[sceneType] || s.imagePipeline.presets.event;
    const detail = [
      `region ${region?.name || 'unknown'} ${region?.biome || 'frontier biome'}`,
      `weather ${s.world.weather.current}`,
      `time phase ${s.time.phase}`,
      `party fatigue index ${Math.round(s.party.roster.reduce((sum, m) => sum + m.fatigue, 0) / Math.max(1, s.party.roster.length))}`,
      `faction pressure ${factionTop?.name || 'none'} standing ${factionTop?.reputation ?? 0}`
    ].join(', ');

    const prompt = `${CONFIG.imagePrompt.basePrefix} ${base}, ${detail} ${CONFIG.imagePrompt.baseSuffix}`.replace(/\s+/g, ' ').trim();
    s.imagePipeline.lastPrompt = prompt;
    s.imagePipeline.history.push({ at: nowIso(), sceneType, prompt });
    s.imagePipeline.history = s.imagePipeline.history.slice(-60);
    return prompt;
  }

  function postSystemToUser(content) {
    oc.thread.messages.push({
      author: 'system',
      content,
      hiddenFrom: ['ai'],
      expectsReply: false
    });
  }

  function injectHiddenContextForAi() {
    oc.thread.messages.push({
      author: 'system',
      content: buildHiddenContext(),
      hiddenFrom: ['user'],
      expectsReply: false
    });
  }

  function statusBrief() {
    const s = Chronicle.state;
    const r = currentRegion();
    return [
      `Chronicle Foundry // Day ${s.time.day} ${String(s.time.hour).padStart(2, '0')}:00 (${s.time.phase})`,
      `Location: ${r?.name || s.world.currentLocation} [${r?.biome || 'unknown'} | danger ${r?.danger ?? '?'}]`,
      `Weather: ${s.world.weather.current} (severity ${s.world.weather.severity}, ${s.world.weather.pressure})`,
      `Resources: food ${s.resources.categories.essentials.food}, water ${s.resources.categories.essentials.water}, medicine ${s.resources.categories.essentials.medicine}, salvage ${s.resources.categories.materials.salvage}`,
      `Load: ${inventoryWeight()}/${s.resources.weightCapacity}`,
      `Party morale avg ${s.party.moraleAverage} | friction ${s.party.frictionIndex} | synergy ${s.party.synergyIndex}`,
      `Contracts active ${s.contracts.active.length}, available ${s.contracts.available.length}, completed ${s.contracts.completed.length}, failed ${s.contracts.failed.length}`,
      `Recent event: ${s.events.lastResolved ? `${s.events.lastResolved.eventId} -> ${s.events.lastResolved.outcome}` : 'none'}`
    ].join('\n');
  }

  function helpText() {
    return [
      'Chronicle Foundry Commands:',
      '/help-engine',
      '/status-engine',
      '/travel <region-id>',
      '/camp',
      '/accept-contract <contract-id>',
      '/progress-contract <contract-id> [risk|safe|standard]',
      '/equip <equipment-id> <party-member-id>',
      '/use <food|water|medicine> <amount>',
      '/snapshot <label>',
      '/restore <snapshot-id>',
      '/new-expedition <optional-seed>',
      '/image-prompt <expedition|landmark|factionPortrait|event>',
      '/ui open | /ui close | /ui screen <name>',
      '/debug on | /debug off',
      '/tutorial skip'
    ].join('\n');
  }

  function commandTrace(command, args, ok, message) {
    Chronicle.state.debug.commandTrace.push({ at: nowIso(), command, args, ok, message });
    Chronicle.state.debug.commandTrace = Chronicle.state.debug.commandTrace.slice(-120);
  }

  function parseCommand(text) {
    if (!text || text[0] !== '/') return null;
    const parts = text.trim().split(/\s+/);
    const command = parts.shift().toLowerCase();
    return { command, args: parts };
  }

  function blockInvalidAction(reason) {
    Chronicle.state.debug.safetyFlags.invalidActionBlocked += 1;
    enqueueNotification('warning', reason);
    return { ok: false, error: reason };
  }

  function handleCommand(command, args) {
    if (command === '/help-engine') {
      postSystemToUser(helpText());
      commandTrace(command, args, true, 'help emitted');
      return true;
    }

    if (command === '/status-engine') {
      postSystemToUser(statusBrief());
      commandTrace(command, args, true, 'status emitted');
      return true;
    }

    if (command === '/travel') {
      const id = safeString(args[0] || '').trim();
      if (!id) {
        postSystemToUser('Usage: /travel <region-id>');
        commandTrace(command, args, false, 'missing region id');
        return true;
      }
      const result = travelTo(id);
      if (!result.ok) {
        postSystemToUser(result.error);
        commandTrace(command, args, false, result.error);
      } else {
        postSystemToUser(`Travel completed to ${getRegionById(id)?.name || id}.`);
        commandTrace(command, args, true, 'travel resolved');
      }
      renderUI(true);
      return true;
    }

    if (command === '/camp') {
      campTurn();
      postSystemToUser('Camp turn resolved.');
      commandTrace(command, args, true, 'camp resolved');
      renderUI(true);
      return true;
    }

    if (command === '/accept-contract') {
      const id = safeString(args[0] || '').trim();
      if (!id) {
        postSystemToUser('Usage: /accept-contract <contract-id>');
        commandTrace(command, args, false, 'missing contract id');
        return true;
      }
      const result = acceptContract(id);
      postSystemToUser(result.ok ? `Accepted contract: ${result.contract.title}` : result.error);
      commandTrace(command, args, result.ok, result.ok ? 'accepted' : result.error);
      renderUI(true);
      return true;
    }

    if (command === '/progress-contract') {
      const id = safeString(args[0] || '').trim();
      const choice = safeString(args[1] || 'standard').trim().toLowerCase();
      if (!id) {
        postSystemToUser('Usage: /progress-contract <contract-id> [risk|safe|standard]');
        commandTrace(command, args, false, 'missing contract id');
        return true;
      }
      const normalized = ['risk', 'safe', 'standard'].includes(choice) ? choice : 'standard';
      const result = progressContract(id, normalized);
      postSystemToUser(result.ok ? `Contract progress updated: ${result.contract.title} (${result.contract.progress}%)` : result.error);
      commandTrace(command, args, result.ok, result.ok ? 'progressed' : result.error);
      renderUI(true);
      return true;
    }

    if (command === '/equip') {
      const eqId = safeString(args[0] || '').trim();
      const memberId = safeString(args[1] || '').trim();
      if (!eqId || !memberId) {
        postSystemToUser('Usage: /equip <equipment-id> <party-member-id>');
        commandTrace(command, args, false, 'missing equip args');
        return true;
      }
      const result = assignEquipment(eqId, memberId);
      postSystemToUser(result.ok ? `Equipment assignment updated (${eqId} -> ${memberId}).` : result.error);
      commandTrace(command, args, result.ok, result.ok ? 'equipment assigned' : result.error);
      renderUI(true);
      return true;
    }

    if (command === '/use') {
      const kind = safeString(args[0] || '').trim().toLowerCase();
      const amount = Number(args[1] || '1');
      if (!['food', 'water', 'medicine'].includes(kind)) {
        postSystemToUser('Usage: /use <food|water|medicine> <amount>');
        commandTrace(command, args, false, 'invalid consumable');
        return true;
      }
      useConsumable(kind, Number.isFinite(amount) ? amount : 1);
      postSystemToUser(`Consumed ${kind}.`);
      commandTrace(command, args, true, 'consumable used');
      renderUI(true);
      return true;
    }

    if (command === '/snapshot') {
      const label = args.join(' ').trim() || undefined;
      const snap = saveSnapshot(label);
      postSystemToUser(snap ? `Snapshot saved: ${snap.id} (${snap.label})` : 'Snapshot failed.');
      commandTrace(command, args, !!snap, snap ? 'snapshot saved' : 'snapshot failed');
      renderUI(true);
      return true;
    }

    if (command === '/restore') {
      const id = safeString(args[0] || '').trim();
      if (!id) {
        postSystemToUser('Usage: /restore <snapshot-id>');
        commandTrace(command, args, false, 'missing snapshot id');
        return true;
      }
      const result = restoreSnapshot(id);
      postSystemToUser(result.ok ? `Snapshot restored: ${id}` : result.error);
      commandTrace(command, args, result.ok, result.ok ? 'snapshot restored' : result.error);
      renderUI(true);
      return true;
    }

    if (command === '/new-expedition') {
      const seed = safeString(args[0] || '').trim();
      resetExpedition(seed || undefined);
      postSystemToUser(`New expedition initialized${seed ? ` (${seed})` : ''}.`);
      commandTrace(command, args, true, 'expedition reset');
      renderUI(true);
      return true;
    }

    if (command === '/image-prompt') {
      const sceneType = safeString(args[0] || 'event').trim();
      const allowed = ['expedition', 'landmark', 'factionPortrait', 'event'];
      if (!allowed.includes(sceneType)) {
        postSystemToUser('Usage: /image-prompt <expedition|landmark|factionPortrait|event>');
        commandTrace(command, args, false, 'invalid image scene type');
        return true;
      }
      const prompt = preBakeImagePrompt(sceneType);
      postSystemToUser(`Image prompt (${sceneType}):\n${prompt}`);
      commandTrace(command, args, true, 'image prompt generated');
      return true;
    }

    if (command === '/ui') {
      const mode = safeString(args[0] || '').trim().toLowerCase();
      if (mode === 'open') {
        toggleUi(true);
        postSystemToUser('Chronicle Foundry UI opened.');
      } else if (mode === 'close') {
        toggleUi(false);
        postSystemToUser('Chronicle Foundry UI closed.');
      } else if (mode === 'screen') {
        const screen = safeString(args[1] || '').trim();
        if (CONFIG.ui.screens.includes(screen)) {
          Chronicle.state.ui.screen = screen;
          toggleUi(true);
          renderUI(true);
          postSystemToUser(`UI screen set to ${screen}.`);
        } else {
          postSystemToUser(`Unknown screen: ${screen}`);
        }
      } else {
        postSystemToUser('Usage: /ui open | /ui close | /ui screen <name>');
      }
      commandTrace(command, args, true, 'ui command handled');
      return true;
    }

    if (command === '/debug') {
      const mode = safeString(args[0] || '').trim().toLowerCase();
      if (mode === 'on') Chronicle.state.debug.enabled = true;
      else if (mode === 'off') Chronicle.state.debug.enabled = false;
      else {
        postSystemToUser('Usage: /debug on | /debug off');
        commandTrace(command, args, false, 'debug usage invalid');
        return true;
      }
      postSystemToUser(`Debug mode ${Chronicle.state.debug.enabled ? 'enabled' : 'disabled'}.`);
      commandTrace(command, args, true, 'debug toggled');
      renderUI(true);
      return true;
    }

    if (command === '/tutorial') {
      const mode = safeString(args[0] || '').trim().toLowerCase();
      if (mode === 'skip') {
        Chronicle.state.ui.tutorialDismissed = true;
        postSystemToUser('Tutorial dismissed. Use /help-engine anytime.');
        commandTrace(command, args, true, 'tutorial skipped');
        renderUI(true);
        return true;
      }
      postSystemToUser('Usage: /tutorial skip');
      commandTrace(command, args, false, 'tutorial usage invalid');
      return true;
    }

    return false;
  }

  function buildNarrativePostprocess(rawContent) {
    const text = safeString(rawContent || '').trim();
    if (!text) return text;
    const hasSitrep = /\bSITREP\b/i.test(text);
    const hasOptions = /\bOPTIONS\b/i.test(text) || /\bNext Actions\b/i.test(text);
    let output = text;
    if (!hasSitrep) output = `SITREP\n${output}`;
    if (!hasOptions) output = `${output}\n\nNext Actions\n- Continue current objective\n- Request status or map update\n- Issue travel or camp command`;
    return output;
  }

  function markProcessed(message, label) {
    message.customData ??= {};
    const key = `${NS}_processed_${label}`;
    if (message.customData[key]) return false;
    message.customData[key] = true;
    return true;
  }

