  function navButton(screen, label) {
    const active = Chronicle.state.ui.screen === screen ? 'active' : '';
    return `<button class="${active}" onclick="window.__pcbw_cf_uiAction('nav','${htmlEscape(screen)}')">${htmlEscape(label)}</button>`;
  }

  function renderDashboard() {
