    const tutorial = s.ui.tutorialDismissed ? '' : `
      <div class="pcbw-cf-card" style="border-color: var(--cf-accent);">
        <div style="font-weight:700;margin-bottom:6px;">First Run Orientation</div>
        <div style="font-size:12px;line-height:1.4;">Use <strong>Map</strong> to travel, <strong>Camp</strong> to recover, <strong>Contracts</strong> to accept and progress objectives, and <strong>Settings</strong> for snapshots and resets. Command alternatives are available in chat via <code>/help-engine</code>.</div>
        <button class="pcbw-cf-btn primary" onclick="window.__pcbw_cf_uiAction('tutorial','dismiss')">Got it</button>
      </div>`;

    return `
      ${tutorial}
      <div class="pcbw-cf-grid">
        <div class="pcbw-cf-card"><div class="pcbw-cf-label">Current Location</div><div class="pcbw-cf-value">${htmlEscape(region?.name || s.world.currentLocation)}</div><div class="pcbw-cf-label">${htmlEscape(region?.biome || '')} · danger ${region?.danger ?? '?'}</div></div>
        <div class="pcbw-cf-card"><div class="pcbw-cf-label">Time</div><div class="pcbw-cf-value">Day ${s.time.day} ${String(s.time.hour).padStart(2, '0')}:00</div><div class="pcbw-cf-label">${htmlEscape(s.time.phase)} · turn ${s.time.turn}</div></div>
        <div class="pcbw-cf-card"><div class="pcbw-cf-label">Weather</div><div class="pcbw-cf-value">${htmlEscape(s.world.weather.current)}</div><div class="pcbw-cf-label">severity ${s.world.weather.severity} · ${htmlEscape(s.world.weather.pressure)}</div></div>
        <div class="pcbw-cf-card"><div class="pcbw-cf-label">Loadout</div><div class="pcbw-cf-value">${load}/${s.resources.weightCapacity}</div><div class="pcbw-cf-label" style="color:${over ? 'var(--cf-danger)' : 'var(--cf-muted)'};">${over ? 'Over capacity' : 'Within capacity'}</div></div>
      </div>
      <div class="pcbw-cf-grid-3">
        <div class="pcbw-cf-card"><div class="pcbw-cf-label">Food</div><div class="pcbw-cf-value">${s.resources.categories.essentials.food}</div></div>
        <div class="pcbw-cf-card"><div class="pcbw-cf-label">Water</div><div class="pcbw-cf-value">${s.resources.categories.essentials.water}</div></div>
        <div class="pcbw-cf-card"><div class="pcbw-cf-label">Medicine</div><div class="pcbw-cf-value">${s.resources.categories.essentials.medicine}</div></div>
      </div>
      <div class="pcbw-cf-card">
        <div style="font-weight:700;margin-bottom:6px;">Party Cohesion</div>
        <div class="pcbw-cf-label">Morale avg ${s.party.moraleAverage} · Friction ${s.party.frictionIndex} · Synergy ${s.party.synergyIndex}</div>
        <button class="pcbw-cf-btn primary" onclick="window.__pcbw_cf_uiAction('turn','camp')">Resolve Camp Turn</button>
        <button class="pcbw-cf-btn" onclick="window.__pcbw_cf_uiAction('nav','map')">Open Map</button>
        <button class="pcbw-cf-btn" onclick="window.__pcbw_cf_uiAction('status','emit')">Emit Status to Chat</button>
      </div>
      <div class="pcbw-cf-card">
