  function renderMap() {
    const s = Chronicle.state;
    const region = currentRegion();
    const connected = listConnectedRegions();
    const discoveredSet = new Set(s.world.discoveredRegions || []);

    const list = connected.map((dest) => {
      const risk = Math.round(dest.danger * 11 + s.world.weather.severity * 5 + s.party.frictionIndex / 6 + (inventoryWeight() > s.resources.weightCapacity ? 12 : 0));
      return `<li>
        <div style="font-weight:600;">${htmlEscape(dest.name)} <span class="pcbw-cf-pill">${htmlEscape(dest.biome)}</span><span class="pcbw-cf-pill">danger ${dest.danger}</span></div>
        <div class="pcbw-cf-label">Risk score: ${risk} · resources: ${htmlEscape((dest.localResources || []).join(', '))}</div>
        <button class="pcbw-cf-btn primary" onclick="window.__pcbw_cf_uiAction('travel','${htmlEscape(dest.id)}')">Travel</button>
      </li>`;
    }).join('');

    const discovered = s.world.regions
      .filter((r) => discoveredSet.has(r.id))
      .map((r) => `<span class="pcbw-cf-pill">${htmlEscape(r.id)} ${htmlEscape(r.name)}</span>`)
      .join(' ');

    return `
      <div class="pcbw-cf-card">
        <div style="font-weight:700;">Current Position: ${htmlEscape(region?.name || s.world.currentLocation)}</div>
        <div class="pcbw-cf-label">Neighbors shown below are valid travel destinations.</div>
      </div>
      <div class="pcbw-cf-card">
        <div style="font-weight:700;margin-bottom:4px;">Connected Regions</div>
        <ul class="pcbw-cf-list">${list || '<li>No routes available</li>'}</ul>
      </div>
      <div class="pcbw-cf-card">
        <div style="font-weight:700;margin-bottom:4px;">Discovered Regions</div>
        <div>${discovered || '<span class="pcbw-cf-label">None</span>'}</div>
      </div>
    `;
  }

  function renderParty() {
    const roster = Chronicle.state.party.roster || [];
    const items = roster.map((m) => {
      const relValues = Object.values(m.relationships || {});
      const relAvg = relValues.length ? Math.round(relValues.reduce((a, b) => a + b, 0) / relValues.length) : 0;
      const cond = (m.conditions || []).length ? m.conditions.join(', ') : 'none';
      return `<li>
        <div style="display:flex;justify-content:space-between;gap:8px;align-items:flex-start;">
          <div>
            <div style="font-weight:600;">${htmlEscape(m.name)} <span class="pcbw-cf-pill">${htmlEscape(m.role)}</span></div>
            <div class="pcbw-cf-label">traits: ${htmlEscape((m.traits || []).join(', '))}</div>
            <div class="pcbw-cf-label">utility: S${m.utility.scouting} M${m.utility.medicine} E${m.utility.engineering} D${m.utility.diplomacy}</div>
            <div class="pcbw-cf-label">conditions: ${htmlEscape(cond)}</div>
          </div>
          <div style="text-align:right;">
            <div class="pcbw-cf-label">morale ${m.morale}</div>
            <div class="pcbw-cf-label">fatigue ${m.fatigue}</div>
            <div class="pcbw-cf-label">rel avg ${relAvg}</div>
          </div>
        </div>
      </li>`;
    }).join('');

    return `
      <div class="pcbw-cf-card">
        <div style="font-weight:700;">Roster (${roster.length})</div>
        <div class="pcbw-cf-label">Friction and synergy update after each travel/camp turn.</div>
      </div>
      <div class="pcbw-cf-card"><ul class="pcbw-cf-list">${items}</ul></div>
    `;
  }

  function renderInventory() {
    const s = Chronicle.state;
    const c = s.resources.categories;

    const eq = s.resources.equipment.map((e) => {
      const assignee = s.party.roster.find((m) => m.id === e.assignedTo);
      const options = s.party.roster.map((m) => `<option value="${htmlEscape(m.id)}">${htmlEscape(m.name)}</option>`).join('');
      return `<li>
        <div style="font-weight:600;">${htmlEscape(e.name)} <span class="pcbw-cf-pill">${htmlEscape(e.utility)}</span></div>
        <div class="pcbw-cf-label">condition ${e.condition} · weight ${e.weight} · assigned ${htmlEscape(assignee?.name || 'none')}</div>
        <div style="margin-top:5px;">
          <select id="pcbw-cf-eq-${htmlEscape(e.id)}" style="font-size:12px;border:1px solid var(--cf-border);background:var(--cf-panel);color:var(--cf-text);border-radius:6px;padding:4px;">${options}</select>
          <button class="pcbw-cf-btn" onclick="window.__pcbw_cf_uiAction('assign-eq','${htmlEscape(e.id)}')">Assign</button>
        </div>
      </li>`;
    }).join('');

    return `
      <div class="pcbw-cf-grid-3">
        <div class="pcbw-cf-card"><div class="pcbw-cf-label">Food</div><div class="pcbw-cf-value">${c.essentials.food}</div><button class="pcbw-cf-btn" onclick="window.__pcbw_cf_uiAction('use','food')">Use 1</button></div>
        <div class="pcbw-cf-card"><div class="pcbw-cf-label">Water</div><div class="pcbw-cf-value">${c.essentials.water}</div><button class="pcbw-cf-btn" onclick="window.__pcbw_cf_uiAction('use','water')">Use 1</button></div>
        <div class="pcbw-cf-card"><div class="pcbw-cf-label">Medicine</div><div class="pcbw-cf-value">${c.essentials.medicine}</div><button class="pcbw-cf-btn warn" onclick="window.__pcbw_cf_uiAction('use','medicine')">Use 1</button></div>
      </div>
      <div class="pcbw-cf-grid-3">
        <div class="pcbw-cf-card"><div class="pcbw-cf-label">Salvage</div><div class="pcbw-cf-value">${c.materials.salvage}</div></div>
        <div class="pcbw-cf-card"><div class="pcbw-cf-label">Fuel Cells</div><div class="pcbw-cf-value">${c.materials.fuelCells}</div></div>
        <div class="pcbw-cf-card"><div class="pcbw-cf-label">Special</div><div class="pcbw-cf-value">Relics ${c.special.relicShards} · Keys ${c.special.signalKeys}</div></div>
      </div>
      <div class="pcbw-cf-card">
        <div style="font-weight:700;">Equipment Assignment</div>
        <ul class="pcbw-cf-list">${eq}</ul>
      </div>
      <div class="pcbw-cf-card"><div class="pcbw-cf-label">Load: ${inventoryWeight()}/${s.resources.weightCapacity}</div></div>
    `;
  }

  function contractCard(c, active) {
    const steps = c.steps.map((s) => `<li>${s.done ? '✅' : '⬜'} ${htmlEscape(s.text)}</li>`).join('');
    const actions = active
      ? `<button class="pcbw-cf-btn" onclick="window.__pcbw_cf_uiAction('contract-progress','${htmlEscape(c.id)}|standard')">Progress</button>
         <button class="pcbw-cf-btn warn" onclick="window.__pcbw_cf_uiAction('contract-progress','${htmlEscape(c.id)}|risk')">Risk Path</button>
         <button class="pcbw-cf-btn" onclick="window.__pcbw_cf_uiAction('contract-progress','${htmlEscape(c.id)}|safe')">Safe Path</button>`
      : `<button class="pcbw-cf-btn primary" onclick="window.__pcbw_cf_uiAction('contract-accept','${htmlEscape(c.id)}')">Accept</button>`;

    return `
      <div class="pcbw-cf-card">
        <div style="font-weight:700;">${htmlEscape(c.title)} <span class="pcbw-cf-pill">${htmlEscape(c.id)}</span></div>
        <div class="pcbw-cf-label">Issuer: ${htmlEscape(c.issuerFaction)} · Region: ${htmlEscape(c.regionName || c.regionId)} · Deadline day ${c.deadlineDay}</div>
        <div class="pcbw-cf-label">Progress ${c.progress}%</div>
        <ul style="margin:6px 0 0 16px;padding:0;font-size:12px;">${steps}</ul>
        <div style="margin-top:6px;font-size:12px;"><strong>Branching:</strong> Risk = ${htmlEscape(c.branching.riskPath)} / Safe = ${htmlEscape(c.branching.safePath)}</div>
        <div>${actions}</div>
      </div>
    `;
  }

  function renderContracts() {
    const active = Chronicle.state.contracts.active.map((c) => contractCard(c, true)).join('') || '<div class="pcbw-cf-card">No active contracts.</div>';
    const available = Chronicle.state.contracts.available.map((c) => contractCard(c, false)).join('') || '<div class="pcbw-cf-card">No available contracts.</div>';

    return `
      <div class="pcbw-cf-card"><strong>Active Contracts</strong><div class="pcbw-cf-label">Progress, branch, and complete to trigger faction/resource consequences.</div></div>
      ${active}
      <div class="pcbw-cf-card"><strong>Available Contracts</strong></div>
      ${available}
    `;
  }

  function renderTimeline() {
    const events = Chronicle.state.events.history.slice(-40).reverse().map((e) => `
      <li>
        <div style="font-weight:600;">${htmlEscape(e.type)} <span class="pcbw-cf-pill">D${e.day} T${e.turn}</span></div>
        <div class="pcbw-cf-label">${htmlEscape(JSON.stringify(e.details || {}).slice(0, 220))}</div>
      </li>
    `).join('');

    const notes = Chronicle.state.notifications.slice(-30).reverse().map((n) => `
      <li><span class="pcbw-cf-pill">${htmlEscape(n.level)}</span> ${htmlEscape(n.text)} <span class="pcbw-cf-label">${htmlEscape(n.at)}</span></li>
    `).join('');

    return `
      <div class="pcbw-cf-card"><strong>Event Log</strong><div class="pcbw-cf-label">Recent simulation events and turn transitions.</div></div>
      <div class="pcbw-cf-card"><ul class="pcbw-cf-list">${events || '<li>No events yet.</li>'}</ul></div>
      <div class="pcbw-cf-card"><strong>Notifications</strong><ul class="pcbw-cf-list">${notes || '<li>No notifications.</li>'}</ul></div>
    `;
  }

  function renderCodex() {
    const entries = Chronicle.state.codex.entries.map((e) => `
      <li>
        <div style="font-weight:600;">${htmlEscape(e.title)} <span class="pcbw-cf-pill">${htmlEscape(e.id)}</span></div>
        <div class="pcbw-cf-label">${htmlEscape(e.body)}</div>
      </li>
    `).join('');

    const discoveries = Chronicle.state.codex.discoveries.slice(-30).reverse().map((d) => `
      <li><div style="font-weight:600;">${htmlEscape(d.title)}</div><div class="pcbw-cf-label">${htmlEscape(d.regionId)} · ${htmlEscape(d.at)}</div></li>
    `).join('');

    return `
      <div class="pcbw-cf-card"><strong>Codex Entries</strong></div>
      <div class="pcbw-cf-card"><ul class="pcbw-cf-list">${entries}</ul></div>
      <div class="pcbw-cf-card"><strong>Discoveries</strong></div>
      <div class="pcbw-cf-card"><ul class="pcbw-cf-list">${discoveries || '<li>No discoveries logged yet.</li>'}</ul></div>
    `;
  }

  function renderFactions() {
    const rows = Object.values(Chronicle.state.factions).map((f) => {
      const stance = f.reputation >= 35 ? 'allied' : f.reputation >= 5 ? 'cooperative' : f.reputation <= -35 ? 'hostile' : f.reputation <= -5 ? 'strained' : 'neutral';
      const tail = (f.recentConsequences || []).slice(-2).map((x) => `${x.delta > 0 ? '+' : ''}${x.delta} ${x.reason}`).join(' | ') || 'no recent changes';
      return `
        <li>
          <div style="font-weight:600;">${htmlEscape(f.name)} <span class="pcbw-cf-pill">${stance}</span></div>
          <div class="pcbw-cf-label">rep ${f.reputation} · leverage ${f.leverage} · risk ${htmlEscape(f.riskLevel)}</div>
          <div class="pcbw-cf-label">${htmlEscape(f.descriptor)}</div>
          <div class="pcbw-cf-label">${htmlEscape(tail)}</div>
        </li>
      `;
    }).join('');

    return `
      <div class="pcbw-cf-card"><strong>Faction Standings</strong><div class="pcbw-cf-label">Reputation shifts alter risk and opportunity cadence.</div></div>
      <div class="pcbw-cf-card"><ul class="pcbw-cf-list">${rows}</ul></div>
    `;
  }

  function renderSettings() {
    const snaps = Chronicle.state.snapshots.slice(-12).reverse().map((s) => `
      <li>
        <div style="font-weight:600;">${htmlEscape(s.label)} <span class="pcbw-cf-pill">${htmlEscape(s.id)}</span></div>
        <div class="pcbw-cf-label">${htmlEscape(s.createdAt)}</div>
        <button class="pcbw-cf-btn" onclick="window.__pcbw_cf_uiAction('restore','${htmlEscape(s.id)}')">Restore</button>
      </li>
    `).join('');

    return `
      <div class="pcbw-cf-card">
        <strong>Save / Snapshot</strong>
        <div class="pcbw-cf-label">Manual snapshots support rollback and recovery.</div>
        <button class="pcbw-cf-btn primary" onclick="window.__pcbw_cf_uiAction('snapshot','manual-ui')">Save Snapshot</button>
        <button class="pcbw-cf-btn warn" onclick="window.__pcbw_cf_uiAction('emit-help','x')">Emit Command Help</button>
      </div>
      <div class="pcbw-cf-card"><ul class="pcbw-cf-list">${snaps || '<li>No snapshots yet.</li>'}</ul></div>
      <div class="pcbw-cf-card">
        <strong>Expedition Control</strong>
        <div class="pcbw-cf-label">Reset creates new seeded world and clears current progression.</div>
        <button class="pcbw-cf-btn danger" onclick="window.__pcbw_cf_uiAction('new-expedition','ui-reset')">New Expedition</button>
        <button class="pcbw-cf-btn" onclick="window.__pcbw_cf_uiAction('ui-close','x')">Close UI</button>
      </div>
    `;
  }

  function renderDebug() {
    const diag = {
      schemaVersion: Chronicle.state.schemaVersion,
      bootedAt: Chronicle.bootedAt,
      eventHandlersRegistered: Chronicle.eventHandlersRegistered,
      timersActive: Chronicle.timers.length,
      saveState: Chronicle.state.saveState,
      safetyFlags: Chronicle.state.debug.safetyFlags,
      lastEvent: Chronicle.state.events.lastResolved,
      currentScene: Chronicle.state.scene,
      imagePipeline: {
        lastPrompt: Chronicle.state.imagePipeline.lastPrompt,
        historyCount: Chronicle.state.imagePipeline.history.length
      }
    };

    const cmdTrace = Chronicle.state.debug.commandTrace.slice(-12).reverse().map((c) => `<li>${htmlEscape(c.at)} · ${htmlEscape(c.command)} · ${c.ok ? 'ok' : 'fail'} · ${htmlEscape(c.message)}</li>`).join('');

    return `
      <div class="pcbw-cf-card">
        <strong>Diagnostics</strong>
        <div class="pcbw-cf-label">Developer-facing state inspection and guard counters.</div>
        <button class="pcbw-cf-btn" onclick="window.__pcbw_cf_uiAction('debug-toggle','x')">Toggle Debug ${Chronicle.state.debug.enabled ? 'Off' : 'On'}</button>
      </div>
      <div class="pcbw-cf-card"><pre class="pcbw-cf-pre">${htmlEscape(JSON.stringify(diag, null, 2))}</pre></div>
      <div class="pcbw-cf-card"><strong>Command Trace</strong><ul class="pcbw-cf-list">${cmdTrace || '<li>No commands traced.</li>'}</ul></div>
    `;
  }

  function renderScreen() {
    const screen = Chronicle.state.ui.screen;
    if (screen === 'dashboard') return renderDashboard();
    if (screen === 'map') return renderMap();
    if (screen === 'party') return renderParty();
    if (screen === 'inventory') return renderInventory();
    if (screen === 'contracts') return renderContracts();
    if (screen === 'timeline') return renderTimeline();
    if (screen === 'codex') return renderCodex();
    if (screen === 'factions') return renderFactions();
    if (screen === 'settings') return renderSettings();
    if (screen === 'debug') return renderDebug();
    return `<div class="pcbw-cf-card">Unknown screen: ${htmlEscape(screen)}</div>`;
  }

  function appMarkup() {
    const s = Chronicle.state;
    const toasts = consumeNotificationsForToast(4).map((n) => `<div class="pcbw-cf-toast ${htmlEscape(n.level)}">${htmlEscape(n.text)}</div>`).join('');

    return `
      <div class="pcbw-cf-app">
        <div class="pcbw-cf-header">
          <div>
            <div style="font-weight:700;">${CONFIG.ui.title}</div>
            <div class="pcbw-cf-label">Day ${s.time.day} · ${String(s.time.hour).padStart(2, '0')}:00 · ${htmlEscape(s.time.phase)} · ${htmlEscape(currentRegion()?.name || s.world.currentLocation)}</div>
          </div>
          <div>
            <button class="pcbw-cf-btn" onclick="window.__pcbw_cf_uiAction('turn','camp')">Camp</button>
            <button class="pcbw-cf-btn" onclick="window.__pcbw_cf_uiAction('status','emit')">Status</button>
            <button class="pcbw-cf-btn" onclick="window.__pcbw_cf_uiAction('ui-close','x')">Close</button>
          </div>
        </div>
        <div class="pcbw-cf-nav">
          ${navButton('dashboard', 'Dashboard')}
          ${navButton('map', 'Map')}
          ${navButton('party', 'Party')}
          ${navButton('inventory', 'Inventory')}
          ${navButton('contracts', 'Contracts')}
          ${navButton('timeline', 'Timeline')}
          ${navButton('codex', 'Codex')}
          ${navButton('factions', 'Factions')}
          ${navButton('settings', 'Settings')}
          ${navButton('debug', 'Debug')}
        </div>
        <div class="pcbw-cf-content">${renderScreen()}</div>
        <div class="pcbw-cf-toast-stack">${toasts}</div>
      </div>
    `;
  }

  function toggleUi(open) {
    Chronicle.state.ui.iframeOpen = !!open;
    if (open) {
      oc.window.show();
      renderUI(true);
    } else {
      oc.window.hide();
    }
  }

  function renderUI(force = false) {
    if (!Chronicle.state.ui.iframeOpen) return;
    ensureStyles();
    const next = appMarkup();
    const digest = String(hashString(next));
    if (!force && Chronicle.lastRenderHash === digest) return;
    Chronicle.lastRenderHash = digest;
    document.body.innerHTML = next;
  }

  function uiAction(type, payload) {
    const p = safeString(payload || '');

    if (type === 'nav') {
      if (CONFIG.ui.screens.includes(p)) {
        Chronicle.state.ui.screen = p;
        renderUI(true);
      }
      saveState();
      return;
    }

    if (type === 'turn' && p === 'camp') {
      campTurn();
      saveState();
      renderUI(true);
      return;
    }

    if (type === 'travel') {
      const result = travelTo(p);
      if (!result.ok) enqueueNotification('warning', result.error);
      saveState();
      renderUI(true);
      return;
    }

    if (type === 'status' && p === 'emit') {
      postSystemToUser(statusBrief());
      saveState();
      renderUI(true);
      return;
    }

    if (type === 'tutorial' && p === 'dismiss') {
      Chronicle.state.ui.tutorialDismissed = true;
      enqueueNotification('info', 'Tutorial dismissed.');
      saveState();
      renderUI(true);
      return;
    }

    if (type === 'contract-accept') {
      const result = acceptContract(p);
      if (!result.ok) enqueueNotification('warning', result.error);
      saveState();
      renderUI(true);
      return;
    }

    if (type === 'contract-progress') {
      const [id, choice] = p.split('|');
      const result = progressContract(id, choice || 'standard');
      if (!result.ok) enqueueNotification('warning', result.error);
      saveState();
      renderUI(true);
      return;
    }

    if (type === 'assign-eq') {
      const select = document.getElementById(`pcbw-cf-eq-${p}`);
      const memberId = select ? safeString(select.value) : '';
      const result = assignEquipment(p, memberId);
      if (!result.ok) enqueueNotification('warning', result.error);
      saveState();
      renderUI(true);
      return;
    }

    if (type === 'use') {
      useConsumable(p, 1);
      saveState();
      renderUI(true);
      return;
    }

    if (type === 'snapshot') {
      saveSnapshot(p || undefined);
      saveState();
      renderUI(true);
      return;
    }

    if (type === 'restore') {
      const result = restoreSnapshot(p);
      if (!result.ok) enqueueNotification('warning', result.error);
      saveState();
      renderUI(true);
      return;
    }

    if (type === 'new-expedition') {
      resetExpedition(p || undefined);
      saveState();
      renderUI(true);
      return;
    }

    if (type === 'emit-help') {
      postSystemToUser(helpText());
      saveState();
      renderUI(true);
      return;
    }

    if (type === 'ui-close') {
      toggleUi(false);
      saveState();
      return;
    }

    if (type === 'debug-toggle') {
      Chronicle.state.debug.enabled = !Chronicle.state.debug.enabled;
      enqueueNotification('info', `Debug ${Chronicle.state.debug.enabled ? 'enabled' : 'disabled'}.`);
      saveState();
      renderUI(true);
      return;
    }
  }

  function installUiActions() {
    window.__pcbw_cf_uiAction = uiAction;
  }

  function configureCharacterPrompting() {
    oc.character.imagePromptPrefix = CONFIG.imagePrompt.basePrefix;
    oc.character.imagePromptSuffix = CONFIG.imagePrompt.baseSuffix;
    oc.character.imagePromptTriggers = 'discovery scene, landmark survey, faction envoy, expedition portrait, weather crisis, contract turn-in, crew recovery';

    oc.character.reminderMessage = [
      'You are an expedition command intelligence.',
      'Keep outputs coherent with explicit state context injected at runtime.',
      'Always provide SITREP + consequence-aware narrative progression + actionable next steps.',
      'Do not echo slash commands as narrative content.',
      'When image prompt context appears, keep it separated from narrative prose.'
    ].join(' ');
  }

  function createImageMessageIfTriggered(userText) {
    const text = safeString(userText).toLowerCase();
    if (!text.includes('image') && !text.includes('visual') && !text.includes('portrait') && !text.includes('illustrate')) return;

    const sceneType = text.includes('faction') ? 'factionPortrait' : (text.includes('landmark') ? 'landmark' : 'event');
    const prompt = preBakeImagePrompt(sceneType);
    oc.thread.messages.push({
      author: 'system',
      content: `Image Prompt Ready (${sceneType}):\n${prompt}`,
      hiddenFrom: ['ai'],
      expectsReply: false
    });
  }

  function processAiMessage(message) {
    if (!markProcessed(message, 'ai')) return;
    message.content = buildNarrativePostprocess(message.content);
  }

  function processUserMessage(message) {
    if (!markProcessed(message, 'user')) return;

    const text = safeString(message.content).trim();
    const parsed = parseCommand(text);

    if (parsed) {
      const index = oc.thread.messages.indexOf(message);
      if (index >= 0) oc.thread.messages.splice(index, 1);
      const handled = handleCommand(parsed.command, parsed.args);
      if (!handled) postSystemToUser(`Unknown engine command: ${parsed.command}. Use /help-engine.`);
      saveState();
      return;
    }

    createImageMessageIfTriggered(text);
    injectHiddenContextForAi();

    Chronicle.state.scene = {
      type: 'negotiation',
      summary: 'User issued narrative directive; runtime context packed for AI continuity.',
      promptFrame: sceneTemplate('negotiation'),
      continuityTags: ['interaction', Chronicle.state.time.phase, Chronicle.state.world.weather.current]
    };

    saveState();
  }

  function seedOnboardingIfNeeded() {
    if (Chronicle.state.ui.onboardingStep > 0) return;
    postSystemToUser('Chronicle Foundry ready. Use /help-engine for command controls and /status-engine for operational brief.');
    Chronicle.state.ui.onboardingStep = 1;
    saveState();
  }

  function setShortcuts() {
    oc.thread.shortcutButtons = [
      { name: 'Status', message: '/status-engine', insertionType: 'replace', autoSend: true, clearAfterSend: true },
      { name: 'Camp', message: '/camp', insertionType: 'replace', autoSend: true, clearAfterSend: true },
      { name: 'Map', message: '/ui screen map', insertionType: 'replace', autoSend: true, clearAfterSend: true },
      { name: 'Contracts', message: '/ui screen contracts', insertionType: 'replace', autoSend: true, clearAfterSend: true },
      { name: 'Snapshot', message: '/snapshot quick', insertionType: 'replace', autoSend: true, clearAfterSend: true },
      { name: 'Image Prompt', message: '/image-prompt event', insertionType: 'replace', autoSend: true, clearAfterSend: true },
      { name: 'Open UI', message: '/ui open', insertionType: 'replace', autoSend: true, clearAfterSend: true },
      { name: 'Help', message: '/help-engine', insertionType: 'replace', autoSend: true, clearAfterSend: true }
    ];
  }

  function startUiRefreshLoop() {
    const id = setInterval(() => {
      if (Chronicle.state.ui.iframeOpen) renderUI(false);
    }, 5000);
    registerTimer(id);
  }

  function startAutosaveLoop() {
    const id = setInterval(() => {
      saveState();
      if (Chronicle.state.time.turn > 0 && Chronicle.state.time.turn % 8 === 0) {
        saveSnapshot(`Auto D${Chronicle.state.time.day}T${Chronicle.state.time.turn}`);
      }
    }, 65000);
    registerTimer(id);
  }

  function registerMessageHandler() {
    if (Chronicle.eventHandlersRegistered) {
      Chronicle.state.debug.safetyFlags.duplicateListenerBlocked = true;
      return;
    }

    oc.thread.on('MessageAdded', async ({ message }) => {
      withRecovery(() => {
        if (!message) return;
        if (message.author === 'user') processUserMessage(message);
        if (message.author === 'ai') processAiMessage(message);
      }, 'MessageAdded');
    });

    Chronicle.eventHandlersRegistered = true;
  }

  function installRuntime() {
    ensureObjects();
    cleanupTimers();

    Chronicle.state = loadState();
    Chronicle.state = migrateState(Chronicle.state) || defaultState();

    if (!validateStateShape(Chronicle.state)) {
      Chronicle.state = defaultState();
      Chronicle.state.debug.safetyFlags.malformedRecoveries += 1;
    }

    configureCharacterPrompting();
    recomputePartyIndices();
    setShortcuts();
    installUiActions();
    registerMessageHandler();
    seedOnboardingIfNeeded();
    startUiRefreshLoop();
    startAutosaveLoop();

    if (Chronicle.state.ui.iframeOpen) {
      toggleUi(true);
    } else {
      toggleUi(false);
    }

    saveState();
  }

  installRuntime();
})();
